1	// Package storage provides a client interface for object storage backends.
2	package storage
3	
4	import (
5		"context"
6		"encoding/json"
7		"fmt"
8		"io"
9		"mime"
10		"mime/multipart"
11		"net/http"
12		"net/textproto"
13		"strings"
14	)
15	
16	// Client abstracts file storage operations so backends can be swapped
17	// or mocked in tests.
18	type Client interface {
19		// Upload stores a file and returns the storage file ID.
20		Upload(ctx context.Context, filename string, reader io.Reader) (fid string, err error)
21		// Download retrieves a file by its storage ID.
22		Download(ctx context.Context, fid string) (io.ReadCloser, error)
23		// Delete removes a file by its storage ID.
24		Delete(ctx context.Context, fid string) error
25	}
26	
27	// assignResponse is the JSON response from SeaweedFS POST /dir/assign.
28	type assignResponse struct {
29		FID       string `json:"fid"`
30		URL       string `json:"url"`
31		PublicURL string `json:"publicUrl"`
32		Count     int    `json:"count"`
33		Error     string `json:"error"`
34	}
35	
36	// SeaweedFSClient interacts with a SeaweedFS cluster over HTTP.
37	type SeaweedFSClient struct {
38		masterURL  string
39		httpClient *http.Client
40	}
41	
42	// NewSeaweedFSClient creates a new SeaweedFS client pointing at the given master URL.
43	func NewSeaweedFSClient(masterURL string, httpClient *http.Client) *SeaweedFSClient {
44		if httpClient == nil {
45			httpClient = http.DefaultClient
46		}
47		// Trim trailing slashes for consistent URL construction.
48		masterURL = strings.TrimRight(masterURL, "/")
49		return &SeaweedFSClient{
50			masterURL:  masterURL,
51			httpClient: httpClient,
52		}
53	}
54	
55	// Upload assigns a file ID from the master, then uploads the file to the
56	// volume server. Returns the assigned fid on success.
57	func (c *SeaweedFSClient) Upload(ctx context.Context, filename string, reader io.Reader) (string, error) {
58		// Step 1: Request a file ID from the master.
59		assignReq, err := http.NewRequestWithContext(ctx, http.MethodPost, c.masterURL+"/dir/assign", nil)
60		if err != nil {
61			return "", fmt.Errorf("seaweedfs assign request: %w", err)
62		}
63	
64		assignResp, err := c.httpClient.Do(assignReq)
65		if err != nil {
66			return "", fmt.Errorf("seaweedfs assign: %w", err)
67		}
68		defer func() { _ = assignResp.Body.Close() }()
69	
70		if assignResp.StatusCode != http.StatusOK {
71			body, _ := io.ReadAll(assignResp.Body)
72			return "", fmt.Errorf("seaweedfs assign: unexpected status %d: %s", assignResp.StatusCode, string(body))
73		}
74	
75		var assign assignResponse
76		if err := json.NewDecoder(assignResp.Body).Decode(&assign); err != nil {
77			return "", fmt.Errorf("seaweedfs assign decode: %w", err)
78		}
79		if assign.Error != "" {
80			return "", fmt.Errorf("seaweedfs assign error: %s", assign.Error)
81		}
82		if assign.FID == "" || assign.URL == "" {
83			return "", fmt.Errorf("seaweedfs assign: empty fid or url")
84		}
85	
86		// Step 2: Upload the file content to the volume server.
