	if w.Code != http.StatusOK {
		t.Errorf("expected 200, got %d: %s", w.Code, w.Body.String())
	}
}

func TestDeleteMe_Success(t *testing.T) {
	svc := &mockUserService{
		deleteMeFn: func(_ context.Context, _ string) error { return nil },
	}
	r := newUserRouter(svc, "user-1")

