    svc := &OrgService{repo: repo}
    if len(wsSvc) > 0 {
        svc.wsSvc = wsSvc[0]
    }
    return svc
}

func (s *OrgService) Create(ctx context.Context, req model.CreateOrgRequest) (*model.Organization, error) {
    slug := toSlug(req.Name)
    if slug == "" {
        return nil, apierror.NewBadRequest("organisation name produces an empty slug")
    }
    org, err := s.repo.Create(ctx, req.Name, slug)
    if err != nil {
        if strings.Contains(err.Error(), "unique") || strings.Contains(err.Error(), "duplicate") {
            return nil, apierror.NewBadRequest("organisation slug already taken: " + slug)
        }
        return nil, apierror.NewInternal("failed to create organisation: " + err.Error())
    }
    // Auto-provision Default workspace
    if s.wsSvc != nil {
        if _, wsErr := s.wsSvc.Create(ctx, org.ID, model.CreateWorkspaceRequest{Name: "Default"}); wsErr != nil {
            slog.Warn("failed to auto-create Default workspace", "org_id", org.ID, "error", wsErr)
        }
    }
    return org, nil
}
```
**Pattern:** Variadic optional dependency, slug validation, unique constraint handling, auto-provision on Create.

